let text = items[0].json.text || items[0].json.output || JSON.stringify(items[0].json);
text = text.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response', raw: text.substring(0, 500) } }];
}

// Build SVG card image
const message = parsed.message || 'No message';
const colors = parsed.colors || ['#f59e0b', '#78350f'];
const c1 = colors[0];
const c2 = colors[1];

// Word wrap the message for SVG
function wrapText(text, maxChars) {
  const words = text.split(' ');
  const lines = [];
  let current = '';
  for (const word of words) {
    if ((current + ' ' + word).trim().length > maxChars) {
      lines.push(current.trim());
      current = word;
    } else {
      current = current ? current + ' ' + word : word;
    }
  }
  if (current.trim()) lines.push(current.trim());
  return lines;
}

const lines = wrapText(message, 28);
const lineHeight = 52;
const startY = 300 - (lines.length * lineHeight / 2);
const textLines = lines.map((line, i) =>
  `<text x="300" y="${startY + i * lineHeight}" text-anchor="middle" fill="white" font-family="Arial, sans-serif" font-size="38" font-weight="bold" style="text-shadow: 0 2px 8px rgba(0,0,0,0.5);">${line.replace(/&/g,'&amp;').replace(/</g,'&lt;')}</text>`
).join('\n');

const insight = (parsed.insight || '').replace(/&/g,'&amp;').replace(/</g,'&lt;');

const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="600" height="600" viewBox="0 0 600 600">
  <defs>
    <linearGradient id="bg" x1="0%" y1="0%" x2="100%" y2="100%">
      <stop offset="0%" stop-color="${c1}" />
      <stop offset="100%" stop-color="${c2}" />
    </linearGradient>
  </defs>
  <rect width="600" height="600" fill="url(#bg)" rx="16" />
  <rect x="30" y="30" width="540" height="540" fill="none" stroke="rgba(255,255,255,0.15)" stroke-width="1" rx="12" />
  ${textLines}
  <text x="300" y="${startY + lines.length * lineHeight + 30}" text-anchor="middle" fill="rgba(255,255,255,0.7)" font-family="Arial, sans-serif" font-size="16" font-style="italic">${insight}</text>
  <text x="300" y="570" text-anchor="middle" fill="rgba(255,255,255,0.4)" font-family="Arial, sans-serif" font-size="12">behivez.co.za</text>
</svg>`;

const svgBase64 = 'data:image/svg+xml;base64,' + Buffer.from(svg).toString('base64');

return [{
  json: {
    message: parsed.message,
    insight: parsed.insight,
    caption: parsed.caption,
    hashtags: parsed.hashtags || [],
    imageSvg: svg,
    imageBase64: svgBase64
  }
}];
